const raw = $input.item.json.content?.[0]?.text || '{}';
const driveFile = $('Google Drive - New Lease Uploaded').item.json;
let analysis;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  analysis = match ? JSON.parse(match[0]) : {};
} catch(e) {
  analysis = { leaseType: 'unknown', tenantName: 'Unknown', tenantEmail: 'unknown@example.com', propertyAddress: 'Unknown', monthlyRent: 0, overallRiskScore: 5, riskFlags: ['Parse error — manual review required'], riskSummary: 'Could not parse lease analysis.' };
}

const riskLevel = analysis.overallRiskScore >= 7 ? 'HIGH' : analysis.overallRiskScore >= 4 ? 'MEDIUM' : 'LOW';
const riskEmoji = riskLevel === 'HIGH' ? ':rotating_light:' : riskLevel === 'MEDIUM' ? ':warning:' : ':white_check_mark:';

return {
  json: {
    ...analysis,
    riskLevel,
    riskEmoji,
    sourceFileName: driveFile.name || 'Lease Document',
    sourceFileId: driveFile.id,
    processedAt: new Date().toISOString()
  }
};

